// components/OfficeTable.jsx

import React from "react";
import CommonTable from "../../../components/CommonTable";

function OfficeTable({
    officelevels,
    searchofficeid,
    selectedsearchOfficeLevel,
    setSelectedSearchOfficeLevel,
    selectedSearchOfficeID,
    setSelectedSearchOfficeID,

    loadOffices,
    loadOfficeList,
    resetFilter,

    offices,
    columns,

    handleEdit,
    handleUpdateStatus
}) {

    return (
        <div className="card">
            <div className="card-header border-0">

                <h5 className="card-title">
                    Office List
                </h5>

                <div className="d-flex gap-2">

                    <select className="form-select form-select-sm" value={selectedValues.searchOfficeLevel}
                        onChange={(e) => { const id = e.target.value; setSelectedValues({ ...selectedValues, searchOfficeLevel: id });
                            loadOffices(id); setSelectedValues({ ...selectedValues, searchOfficeID: "" }); }} >
                        <option value=""> Select Office Level </option>
                        {officelevels.map(level => (
                            <option
                                key={level.office_level_id}
                                value={level.office_level_id}
                            >
                                {level.office_level_name}
                            </option>
                        ))}
                    </select>

                    <select className="form-select form-select-sm" value={selectedValues.searchOfficeID}
                        onChange={(e) => setSelectedValues({ ...selectedValues, searchOfficeID: e.target.value }) } >
                        <option value=""> Select Office </option>
                        {searchofficeid.map(office => (
                            <option
                                key={office.office_id}
                                value={office.office_id}
                            >
                                {office.office_name}
                            </option>
                        ))}
                    </select>

                    <button
                        className="btn btn-primary btn-sm"
                        onClick={() =>
                            loadOfficeList(
                                selectedsearchOfficeLevel,
                                selectedSearchOfficeID
                            )
                        }
                    >
                        <i className="fa fa-search"></i>
                    </button>

                    <button
                        className="btn btn-danger btn-sm"
                        onClick={resetFilter}
                    >
                        <i className="fa fa-refresh"></i>
                    </button>

                </div>
            </div>

            <div className="card-body">

                <CommonTable
                    data={offices}
                    columns={columns}
                    rowsPerPage={10}
                    renderActions={(b) => (
                        <>
                            <button
                                className="btn btn-warning btn-sm"
                                onClick={() => handleEdit(b)}
                            >
                                <i className="fa fa-edit text-white"></i>
                            </button>

                            <button
                                className="btn btn-danger btn-sm"
                                onClick={() =>
                                    handleUpdateStatus(b, "R")
                                }
                            >
                                <i className="fa fa-trash text-white"></i>
                            </button>

                            {b.status === "A" ? (
                                <button
                                    className="btn btn-danger btn-sm"
                                    onClick={() =>
                                        handleUpdateStatus(b, "D")
                                    }
                                >
                                    <i className="fa fa-toggle-on text-white"></i>
                                </button>
                            ) : (
                                <button
                                    className="btn btn-success btn-sm"
                                    onClick={() =>
                                        handleUpdateStatus(b, "A")
                                    }
                                >
                                    <i className="fa fa-toggle-off text-white"></i>
                                </button>
                            )}
                        </>
                    )}
                />

            </div>
        </div>
    );
}

export default OfficeTable;
